# Sort keys alphabetically
keys = sorted(data.keys())

with open("D:\\PROJECTS\\procncmaroc\\frontend\\src\\data\\countries.js", "w", encoding="utf-8") as f:
    f.write("const countries = {\n")
    for k in keys:
        cities = sorted(data[k])
        # Determine if key needs quotes (contains non-alphanumeric chars)
        if any(c in k for c in ["'", " ", "-"]):
            escaped_key = k.replace("'", "\\'")
            line = f"  '{escaped_key}': ["
        else:
            line = f"  {k}: ["
        city_strs = []
        for c in cities:
            if "'" in c:
                city_strs.append(f'"{c}"')
            else:
                city_strs.append(f"'{c}'")
        line += ", ".join(city_strs) + "],"
        f.write(line + "\n")
    f.write("};\n")
    f.write("export default countries;\n")

